// 2.8.5 | 2024-12-05 | RAJ  |  ServiceNow Certifier Update - Modified to use GlideStringUtil.escapeQueryTermSeparator
// 2.7.1 | 2021-12-19 | raj | DFCT0010296 - HHS: If user is in two OU and is remove/deleted from their default/primary OU, their default OU is not updated. 
// Script Continued Below
(function executeRule(current, previous /*null when async*/ ) {

	var userFullName;
	var msgRemoveUser;
	var defaultOUID;
	var OUID;
	var OrganizationalOU = new OrganizationalScripts();
    var UserPermissions = new UserInfoScripts();
    // before removing global roles, determine if the user has been removed from all OU's
    var grMemOUs = new GlideRecordSecure("x_153465_discovert_discover_office_members");
    // before removing global roles, determine if the user has been removed from all OU's
    var grUser = new GlideRecordSecure("x_153465_discovert_organization_user");

	OrganizationalOU.RemoveMemberAsTaskingAuthority(current.discover_office_hierarchy + '', current.office_member + '');
	//STRY0059849 - making OU HA similar to TM
	OrganizationalOU.RemoveMemberAsOUHierarchyAdmin(current.discover_office_hierarchy + '', current.office_member + '');
    // STRY0046028, STRY0085149

	if(grUser.get(current.getValue("u_organizational_user"))){
		// ServiceNow Certifier Update - not changing, no way for user to inject into this query - update later with more time
		grMemOUs.addQuery('office_member', current.office_member + '');
		grMemOUs.query();
		// if there are still OUs this member is in, do not remove global roles.  If not, remove global roles.
		if (grMemOUs.next()) {
			defaultOUID = grUser.getValue("u_default_ou");
			OUID = current.getValue("discover_office_hierarchy");
			// 
			if(defaultOUID == OUID){
				UserPermissions.setNewDefaultOU(current.office_member);
			}
		} else {
			userFullName = grUser.u_tasker_user.first_name + ' ' + grUser.u_tasker_user.middle_name + ' ' + grUser.u_tasker_user.last_name;
			msgRemoveUser = gs.getMessage("The User {0} was removed from all offices, {0} is now inactive, and all permissions have been removed{0}",[userFullName]);
			grUser.active = false;
			grUser.u_default_ou = "";
			grUser.update(msgRemoveUser);
			gs.addInfoMessage(msgRemoveUser);
		}
	}
})(current, previous);
